import { ExclusionGroupsDialog } from "../tool-editor/dialogs/exclusion-groups-dialog";
import { ParameterDetailsDialog } from "../tool-editor/dialogs/parameter-details-dialog";
import { ToolDetailsDialog } from "../tool-editor/dialogs/tool-details-dialog";
import { CommandTree } from "./command-tree";
import { SavedCommandsDialog } from "./dialogs/saved-commands-dialog";
import { ParameterList } from "./parameter-list";
import { PreviewTabs } from "./preview-tabs";
import { toolBuilderActions, toolBuilderStore } from "./tool-editor.store";
import { Button } from "@/components/ui/button";
import { SavedCommand, Tool } from "@/registry/commandly/lib/types/commandly";
import {
  getSavedCommandsFromStorage,
  removeSavedCommandFromStorage,
} from "@/registry/commandly/lib/utils/commandly";
import { useStore } from "@tanstack/react-store";
import { SaveIcon, Edit2Icon, LayersIcon, GitPullRequestIcon } from "lucide-react";
import { useEffect, useState } from "react";
import { toast } from "sonner";

const GITHUB_REPO = "divyeshio/commandly";
const MAX_URL_JSON_LENGTH = 4000;

interface ToolEditorProps {
  tool: Tool;
  onSave?: (tool: Tool) => void;
  isNewTool?: boolean;
}

export default function ToolEditor({
  tool: toolToEdit,
  onSave,
  isNewTool = false,
}: ToolEditorProps) {
  const tool = useStore(toolBuilderStore, (state) => state.tool);

  useEffect(() => {
    toolBuilderActions.initializeTool(toolToEdit);
  }, [toolToEdit]);

  const [savedCommands, setSavedCommands] = useState<SavedCommand[]>([]);

  const handleContribute = async () => {
    const currentTool = toolBuilderStore.state.tool;
    const json = JSON.stringify(currentTool, null, 2);
    const filePath = `public/tools-collection/${currentTool.name}.json`;

    if (isNewTool) {
      const message = encodeURIComponent(`feat(tools): add ${currentTool.name}`);
      const filename = encodeURIComponent(filePath);
      if (json.length <= MAX_URL_JSON_LENGTH) {
        window.open(
          `https://github.com/${GITHUB_REPO}/new/main?filename=${filename}&value=${encodeURIComponent(json)}&message=${message}`,
          "_blank",
        );
      } else {
        await navigator.clipboard.writeText(json);
        toast("JSON copied to clipboard", {
          description: "Paste it into the file editor that will open.",
        });
        window.open(
          `https://github.com/${GITHUB_REPO}/new/main?filename=${filename}&message=${message}`,
          "_blank",
        );
      }
    } else {
      await navigator.clipboard.writeText(json);
      toast("JSON copied to clipboard", {
        description: "Paste it into the file editor that will open to create a PR.",
      });
      window.open(`https://github.com/${GITHUB_REPO}/edit/main/${filePath}`, "_blank");
    }
  };

  const handleDeleteCommand = (commandKey: string) => {
    const toolId = tool.name;
    removeSavedCommandFromStorage(`saved-${toolId}`, commandKey);
    setSavedCommands(savedCommands.filter((cmd) => cmd.key !== commandKey));
  };

  return (
    <div className="flex bg-background">
      <div className="flex w-72 flex-col overflow-hidden border-r border-muted">
        <div className="flex flex-col justify-center gap-2 border-b border-muted p-2">
          <p className="p-3">Commands</p>
        </div>
        <CommandTree />
      </div>

      {/* Main Content */}
      <div className="flex flex-1 flex-col">
        <div className="border-b border-muted p-4">
          <div className="flex justify-between">
            <div className="flex items-center justify-between gap-2">
              <span
                className="text-lg font-medium"
                style={{
                  viewTransitionName: `tool-card-title-${tool.name}`,
                }}
              >
                {tool.displayName ? `${tool.displayName} (${tool.name})` : `${tool.name}`}
              </span>
              <Button
                variant="ghost"
                size="sm"
                className="h-6 w-6 p-0"
                onClick={() => toolBuilderActions.setDialogOpen("editTool", true)}
              >
                <Edit2Icon className="h-4 w-4" />
              </Button>
            </div>
            <div className="flex items-center gap-2">
              {onSave && (
                <Button
                  variant="default"
                  size="sm"
                  onClick={() => {
                    onSave(toolBuilderStore.state.tool);
                    toast("Tool saved successfully!");
                  }}
                >
                  <SaveIcon className="mr-2 h-4 w-4" />
                  Save
                </Button>
              )}
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  const toolId = tool.name;
                  const commands = getSavedCommandsFromStorage(toolId);
                  setSavedCommands(commands);
                  toolBuilderActions.setDialogOpen("savedCommands", true);
                }}
              >
                <SaveIcon className="mr-2 h-4 w-4" />
                Saved Commands
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => toolBuilderActions.setDialogOpen("exclusionGroups", true)}
              >
                <LayersIcon className="mr-2 h-4 w-4" />
                Exclusion Groups
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={handleContribute}
              >
                <GitPullRequestIcon className="mr-2 h-4 w-4" />
                Contribute
              </Button>
            </div>
          </div>
        </div>

        <div className="flex content-between gap-4 p-4">
          <div className="flex min-w-80 flex-2/5 flex-col gap-4">
            <ParameterList
              title="Global Parameters"
              isGlobal={true}
            />
            <ParameterList
              title="Command Parameters"
              isGlobal={false}
            />
          </div>
          <div className="max-w-3xl flex-3/5">
            <PreviewTabs />
          </div>
        </div>
      </div>

      <ParameterDetailsDialog />
      <ToolDetailsDialog />
      <SavedCommandsDialog
        savedCommands={savedCommands}
        onDeleteCommand={handleDeleteCommand}
      />
      <ExclusionGroupsDialog />
    </div>
  );
}

import {
  Tool,
  Command,
  Parameter,
  ExclusionGroup,
  ParameterValue,
  SavedCommand,
} from "@/registry/commandly/lib/types/commandly";
import {
  addSavedCommandToStorage,
  createNewCommand,
  defaultTool,
  getAllSubcommands,
  getSavedCommandsFromStorage,
  removeSavedCommandFromStorage,
  slugify,
} from "@/registry/commandly/lib/utils/commandly";
import { Store } from "@tanstack/react-store";
import { toast } from "sonner";

export interface ToolBuilderState {
  tool: Tool;
  selectedCommand: Command;
  selectedParameter: Parameter | null;
  editingCommand: Command | null;
  parameterValues: Record<string, ParameterValue>;
  dialogs: {
    parameterDetails: boolean;
    editTool: boolean;
    savedCommands: boolean;
    exclusionGroups: boolean;
  };
}

export const toolBuilderStore = new Store<ToolBuilderState>({
  tool: defaultTool(),
  selectedCommand: {} as Command,
  selectedParameter: null,
  editingCommand: null,
  parameterValues: {},
  dialogs: {
    parameterDetails: false,
    editTool: false,
    savedCommands: false,
    exclusionGroups: false,
  },
});

export const toolBuilderSelectors = {
  getParametersForCommand: (state: ToolBuilderState, commandKey: string): Parameter[] => {
    return state.tool.parameters.filter((param: Parameter) => {
      if (param.isGlobal) return false;
      return param.commandKey === commandKey;
    });
  },

  getGlobalParameters: (state: ToolBuilderState): Parameter[] => {
    return state.tool.parameters.filter((param: Parameter) => param.isGlobal);
  },

  getExclusionGroupsForCommand: (state: ToolBuilderState, commandKey: string): ExclusionGroup[] => {
    return (
      state.tool.exclusionGroups?.filter((group: ExclusionGroup) => {
        return group.commandKey === commandKey;
      }) ?? []
    );
  },
};

export const toolBuilderActions = {
  initializeTool(tool: Tool) {
    toolBuilderStore.setState((state) => ({
      ...state,
      tool,
      selectedCommand: tool.commands[0],
    }));
  },

  updateTool(updates: Partial<Tool>) {
    toolBuilderStore.setState((state) => ({
      ...state,
      tool: {
        ...state.tool,
        ...updates,
      },
    }));
  },

  addSubcommand(parentKey?: string) {
    const newCommand = createNewCommand(parentKey);
    toolBuilderStore.setState((state) => ({
      ...state,
      tool: {
        ...state.tool,
        commands: [...state.tool.commands, newCommand],
      },
    }));

    toast("Command Added", {
      description: "New command has been created successfully.",
    });
  },

  deleteCommand(commandKey: string) {
    toolBuilderStore.setState((state) => {
      const subcommands = getAllSubcommands(commandKey, state.tool.commands);
      const commandsToDelete = [commandKey, ...subcommands.map((c) => c.key)];

      const newState = {
        ...state,
        tool: {
          ...state.tool,
          commands: state.tool.commands.filter((cmd) => !commandsToDelete.includes(cmd.key)),
          parameters: state.tool.parameters.filter(
            (param) => !commandsToDelete.includes(param.commandKey || ""),
          ),
          exclusionGroups: state.tool.exclusionGroups?.filter(
            (group) => !commandsToDelete.includes(group.commandKey || ""),
          ),
        },
      };

      if (state.selectedCommand?.key === commandKey) {
        newState.selectedCommand = newState.tool.commands[0];
      }

      return newState;
    });

    toast("Command Deleted", {
      description: "Command and all its subcommands have been deleted.",
    });
  },

  updateCommand(commandKey: string, updates: Partial<Command>) {
    toolBuilderStore.setState((state) => ({
      ...state,
      tool: {
        ...state.tool,
        commands: state.tool.commands.map((cmd) => {
          let updatedCmd: Command;
          if (cmd.key === commandKey) {
            updatedCmd = { ...cmd, ...updates };
          } else {
            if (!updates.isDefault) updatedCmd = cmd;
            else {
              updatedCmd = { ...cmd, isDefault: false };
            }
          }
          return updatedCmd;
        }),
      },
    }));
  },

  removeParameter(parameterKey: string) {
    toolBuilderStore.setState((state) => {
      const newState = {
        ...state,
        tool: {
          ...state.tool,
          parameters: state.tool.parameters.filter((param) => param.key !== parameterKey),
          exclusionGroups: state.tool.exclusionGroups?.map((group) => ({
            ...group,
            parameterKeys: group.parameterKeys.filter((key) => key !== parameterKey),
          })),
        },
      };

      if (state.selectedParameter?.key === parameterKey) {
        newState.selectedParameter = null;
      }

      return newState;
    });

    toast("Parameter Deleted", {
      description: "Parameter has been removed successfully.",
    });
  },
  addSavedCommand(command: string) {
    const toolId = toolBuilderStore.state.tool.name; // Use tool name as id
    const existingCommands = getSavedCommandsFromStorage(toolId);
    if (existingCommands.some((cmd) => cmd.command === command)) {
      toast.error("Command already exists", {
        description: "This command has already been saved.",
      });
      return;
    }
    const newSavedCommand: SavedCommand = {
      key: slugify(command.substring(0, 20)),
      command,
    };

    addSavedCommandToStorage(`saved-${toolId}`, newSavedCommand);

    toast("Command Saved", {
      description: "Command has been saved successfully.",
    });
  },

  removeSavedCommand(commandKey: string) {
    toolBuilderStore.setState((state) => {
      const toolId = state.tool.name;
      removeSavedCommandFromStorage(`saved-${toolId}`, commandKey);
      return { ...state };
    });
  },

  addExclusionGroup(group: Omit<ExclusionGroup, "key">) {
    toolBuilderStore.setState((state) => {
      const newGroup = {
        ...group,
        key: slugify(group.name),
        commandKey: state.selectedCommand?.key,
      };

      return {
        ...state,
        tool: {
          ...state.tool,
          exclusionGroups: [...(state.tool.exclusionGroups ?? []), newGroup],
        },
      };
    });

    toast("Group Added", {
      description: "New exclusion group has been created successfully.",
    });
  },

  updateExclusionGroup(updatedGroup: ExclusionGroup) {
    toolBuilderStore.setState((state) => ({
      ...state,
      tool: {
        ...state.tool,
        exclusionGroups: state.tool.exclusionGroups?.map((group) =>
          group.key === updatedGroup.key ? updatedGroup : group,
        ),
      },
    }));

    toast("Group Updated", {
      description: "Exclusion group has been updated successfully.",
    });
  },

  removeExclusionGroup(groupKey: string) {
    toolBuilderStore.setState((state) => ({
      ...state,
      tool: {
        ...state.tool,
        exclusionGroups: state.tool.exclusionGroups?.filter((group) => group.key !== groupKey),
      },
    }));

    toast("Group Removed", {
      description: "Exclusion group has been removed successfully.",
    });
  },

  setDialogOpen(
    dialog: "editTool" | "savedCommands" | "exclusionGroups" | "parameterDetails",
    open: boolean,
  ) {
    toolBuilderStore.setState((state) => ({
      ...state,
      dialogs: {
        ...state.dialogs,
        [dialog]: open,
      },
    }));
  },

  setSelectedCommand(command: Command) {
    toolBuilderStore.setState((state) => ({
      ...state,
      selectedCommand: command,
    }));
  },

  setSelectedParameter(parameter: Parameter | null) {
    toolBuilderStore.setState((state) => ({
      ...state,
      selectedParameter: parameter,
    }));
  },

  setEditingCommand(command: Command | null) {
    toolBuilderStore.setState((state) => ({
      ...state,
      editingCommand: command,
    }));
  },

  upsertParameter(parameter: Parameter) {
    toolBuilderStore.setState((state) => {
      const exists = state.tool.parameters.some((p) => p.key === parameter.key);
      let newParameters: Parameter[];
      if (exists) {
        newParameters = state.tool.parameters.map((param) => {
          if (param.key === parameter.key) {
            const updatedParam = {
              ...param,
              ...parameter,
              dependencies: parameter.dependencies || [],
              validations: parameter.validations || [],
              enumValues: parameter.enumValues || [],
            };
            if (parameter.isGlobal && parameter.isGlobal !== param.isGlobal) {
              updatedParam.commandKey = undefined;
            }
            if (parameter.isGlobal === false && param.isGlobal) {
              updatedParam.commandKey = state.selectedCommand?.key;
            }
            return updatedParam;
          }
          return param;
        });
        toast("Parameter Updated", {
          description: `Parameter has been updated successfully.`,
        });
      } else {
        newParameters = [...state.tool.parameters, parameter];
        toast("Parameter Added", {
          description: `New ${parameter.isGlobal ? "global " : ""}parameter has been created successfully.`,
        });
      }
      return {
        ...state,
        tool: {
          ...state.tool,
          parameters: newParameters,
        },
      };
    });
  },
};

import { CommandDialog } from "../tool-editor/dialogs/command-dialog";
import { toolBuilderStore, toolBuilderActions } from "./tool-editor.store";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Command } from "@/registry/commandly/lib/types/commandly";
import { useStore } from "@tanstack/react-store";
import { ChevronDownIcon, ChevronRightIcon, Edit2Icon, PlusIcon, Trash2Icon } from "lucide-react";
import { useState, useEffect } from "react";

interface CommandNodeProps {
  command: Command;
  level?: number;
  allCommands: Command[];
  toolName: string;
  selectedCommandKey?: string;
  expandedCommands: Set<string>;
  onToggle: (commandKey: string) => void;
  onEdit: (command: Command) => void;
  onAddSubcommand: (parentKey?: string) => void;
  onDelete: (commandKey: string) => void;
}

function CommandNode({
  command,
  level = 0,
  allCommands,
  toolName,
  selectedCommandKey,
  expandedCommands,
  onToggle,
  onEdit,
  onAddSubcommand,
  onDelete,
}: CommandNodeProps) {
  const isExpanded = expandedCommands.has(command.key);
  const subcommands = allCommands.filter((cmd) => cmd.parentCommandKey === command.key);
  const hasSubcommands = subcommands.length > 0;
  const isSelected = selectedCommandKey === command.key;
  const isRoot = command.name === toolName;

  return (
    <div key={command.key}>
      <div
        className={`group flex cursor-pointer items-center gap-2 rounded-md p-2 hover:bg-muted/50 ${
          isSelected ? "bg-muted" : ""
        }`}
        style={{ paddingLeft: `${level * 16 + 8}px` }}
        onClick={() => toolBuilderActions.setSelectedCommand(command)}
      >
        {hasSubcommands ? (
          <Button
            id="expand-button"
            variant="ghost"
            size="sm"
            className="h-4 w-4 p-0"
            onClick={(e) => {
              e.stopPropagation();
              onToggle(command.key);
            }}
          >
            {isExpanded ? (
              <ChevronDownIcon className="h-3 w-3" />
            ) : (
              <ChevronRightIcon className="h-3 w-3" />
            )}
          </Button>
        ) : (
          <div className="w-4" />
        )}

        <span className="flex-1 text-sm font-medium">{command.name}</span>
        {command.isDefault && (
          <Badge
            variant="secondary"
            className="text-xs"
          >
            default
          </Badge>
        )}
        <Button
          variant="ghost"
          size="sm"
          className="h-4 w-4 p-0 opacity-0 group-hover:opacity-100"
          onClick={(e) => {
            e.stopPropagation();
            onEdit(command);
          }}
        >
          <Edit2Icon className="h-3 w-3" />
        </Button>
        <Button
          variant="ghost"
          size="sm"
          className="h-4 w-4 p-0 opacity-0 group-hover:opacity-100"
          onClick={(e) => {
            e.stopPropagation();
            onAddSubcommand(command.key);
          }}
        >
          <PlusIcon className="h-3 w-3" />
        </Button>
        {!isRoot && (
          <Button
            variant="ghost"
            size="sm"
            className="h-4 w-4 p-0 opacity-0 group-hover:opacity-100"
            onClick={(e) => {
              e.stopPropagation();
              onDelete(command.key);
            }}
          >
            <Trash2Icon className="h-3 w-3 text-destructive" />
          </Button>
        )}
      </div>

      {isExpanded && hasSubcommands && (
        <div>
          {subcommands.map((subcmd) => (
            <CommandNode
              key={subcmd.key}
              command={subcmd}
              level={level + 1}
              allCommands={allCommands}
              toolName={toolName}
              selectedCommandKey={selectedCommandKey}
              expandedCommands={expandedCommands}
              onToggle={onToggle}
              onEdit={onEdit}
              onAddSubcommand={onAddSubcommand}
              onDelete={onDelete}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export function CommandTree() {
  const tool = useStore(toolBuilderStore, (state) => state.tool);
  const selectedCommand = useStore(toolBuilderStore, (state) => state.selectedCommand);
  const editingCommand = useStore(toolBuilderStore, (state) => state.editingCommand);

  const [expandedCommands, setExpandedCommands] = useState<Set<string>>(
    new Set([tool.commands[0]?.key]),
  );
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [lastAddedCommand, setLastAddedCommand] = useState<{
    key: string;
    parentKey?: string;
  } | null>(null);

  const toggleExpanded = (commandKey: string) => {
    setExpandedCommands((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(commandKey)) {
        newSet.delete(commandKey);
      } else {
        newSet.add(commandKey);
      }
      return newSet;
    });
  };

  // Patch toolBuilderActions.addSubcommand to select and expand parent after add
  const handleAddSubcommand = (parentKey?: string) => {
    const prevKeys = new Set(tool.commands.map((cmd) => cmd.key));
    toolBuilderActions.addSubcommand(parentKey);
    const newCmd = toolBuilderStore.state.tool.commands.find((cmd) => !prevKeys.has(cmd.key));
    if (newCmd) {
      setLastAddedCommand({ key: newCmd.key, parentKey });
    }
  };

  useEffect(() => {
    if (!lastAddedCommand) return;
    const { key, parentKey } = lastAddedCommand;
    const newCmd = tool.commands.find((cmd) => cmd.key === key);
    if (newCmd) {
      toolBuilderActions.setSelectedCommand(newCmd);
      if (parentKey) {
        setExpandedCommands((prev) => {
          const newSet = new Set(prev);
          newSet.add(parentKey);
          return newSet;
        });
      }
      setLastAddedCommand(null);
    }
  }, [tool.commands, lastAddedCommand]);

  const handleEdit = (command: Command) => {
    toolBuilderActions.setEditingCommand(command);
    setIsDialogOpen(true);
  };

  const rootCommands = tool.commands.filter((cmd) => !cmd.parentCommandKey);

  return (
    <>
      <ScrollArea className="flex-1 p-1">
        <div className="p-2">
          {rootCommands.map((command) => (
            <CommandNode
              key={command.key}
              command={command}
              allCommands={tool.commands}
              toolName={tool.name}
              selectedCommandKey={selectedCommand?.key}
              expandedCommands={expandedCommands}
              onToggle={toggleExpanded}
              onEdit={handleEdit}
              onAddSubcommand={handleAddSubcommand}
              onDelete={toolBuilderActions.deleteCommand}
            />
          ))}
        </div>
        <div className="p-2">
          <Button
            className="w-full"
            onClick={() => handleAddSubcommand()}
          >
            <PlusIcon className="mr-1 h-3 w-3" />
            Add Command
          </Button>
        </div>
      </ScrollArea>
      {editingCommand && (
        <CommandDialog
          isOpen={isDialogOpen}
          onOpenChange={(open) => {
            setIsDialogOpen(open);
            toolBuilderActions.setEditingCommand(null);
          }}
        />
      )}
    </>
  );
}

import {
  ToolBuilderState,
  toolBuilderStore,
  toolBuilderActions,
  toolBuilderSelectors,
} from "./tool-editor.store";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { ExclusionGroup, ParameterType } from "@/registry/commandly/lib/types/commandly";
import { createNewParameter, validateDefaultValue } from "@/registry/commandly/lib/utils/commandly";
import { useStore } from "@tanstack/react-store";
import {
  CheckCircleIcon,
  FileTextIcon,
  FlagIcon,
  GlobeIcon,
  HashIcon,
  LayersIcon,
  PlusIcon,
  Trash2Icon,
  XCircleIcon,
} from "lucide-react";

interface ParameterListProps {
  title: string;
  isGlobal?: boolean;
}

function ParameterIcon({ type }: { type: ParameterType }) {
  switch (type) {
    case "Flag":
      return <FlagIcon className="h-4 w-4" />;
    case "Option":
      return <HashIcon className="h-4 w-4" />;
    case "Argument":
      return <FileTextIcon className="h-4 w-4" />;
    default:
      return <HashIcon className="h-4 w-4" />;
  }
}

export function ParameterList({ title, isGlobal = false }: ParameterListProps) {
  const selectedCommand = useStore(toolBuilderStore, (state) => state.selectedCommand);
  const globalParameters = useStore(toolBuilderStore, (state) =>
    toolBuilderSelectors.getGlobalParameters(state),
  );
  const commandParameters = useStore(toolBuilderStore, (state: ToolBuilderState) =>
    selectedCommand?.key
      ? toolBuilderSelectors.getParametersForCommand(state, selectedCommand.key)
      : [],
  );
  const exclusionGroups = useStore(toolBuilderStore, (state: ToolBuilderState) =>
    selectedCommand?.key
      ? toolBuilderSelectors.getExclusionGroupsForCommand(state, selectedCommand.key)
      : [],
  );

  const parameters = isGlobal ? globalParameters : commandParameters;

  const getParameterExclusionGroups = (parameterKey: string): ExclusionGroup[] => {
    return exclusionGroups.filter((group) => group.parameterKeys.includes(parameterKey));
  };

  return (
    <div>
      <div className="mb-4 flex items-center justify-between">
        <h3 className="flex items-center gap-2 text-lg font-semibold">
          {isGlobal && <GlobeIcon className="h-5 w-5" />}
          {title} ({parameters.length})
        </h3>
        <Button
          onClick={() =>
            toolBuilderActions.setSelectedParameter(
              createNewParameter(isGlobal, selectedCommand?.key),
            )
          }
          size="sm"
        >
          <PlusIcon className="h-4 w-4" />
        </Button>
      </div>

      <div className="space-y-2">
        {parameters.map((parameter) => {
          const validation = validateDefaultValue(parameter);
          const paramGroups = getParameterExclusionGroups(parameter.key);

          return (
            <div
              key={parameter.key}
              className={"cursor-pointer rounded border p-3 hover:bg-muted/50"}
              onClick={() => toolBuilderActions.setSelectedParameter(parameter)}
            >
              <div className="mb-2 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <ParameterIcon type={parameter.parameterType} />
                  <span className="text-sm font-medium">
                    {parameter.name}
                    {(parameter.longFlag || parameter.shortFlag) && (
                      <span className="ml-1 text-muted-foreground">
                        ({[parameter.longFlag, parameter.shortFlag].filter(Boolean).join(", ")})
                      </span>
                    )}
                  </span>
                </div>
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-6 w-6 p-0"
                  onClick={(e) => {
                    e.stopPropagation();
                    toolBuilderActions.removeParameter(parameter.key);
                  }}
                >
                  <Trash2Icon className="h-3 w-3 text-destructive" />
                </Button>
              </div>
              <div className="flex flex-wrap items-center gap-1">
                {parameter.isRequired && (
                  <Badge
                    variant="destructive"
                    className="text-xs"
                  >
                    required
                  </Badge>
                )}
                <Badge
                  variant="outline"
                  className="text-xs"
                >
                  {parameter.parameterType}
                </Badge>
                <Badge
                  variant="secondary"
                  className="text-xs"
                >
                  {parameter.dataType}
                </Badge>
                {isGlobal && (
                  <Badge
                    variant="default"
                    className="text-xs"
                  >
                    global
                  </Badge>
                )}
                {paramGroups.map((group) => (
                  <Badge
                    key={group.key}
                    variant="secondary"
                    className="flex items-center gap-1 bg-muted text-xs"
                  >
                    <LayersIcon className="h-3 w-3" />
                    {group.name}
                  </Badge>
                ))}
                {!validation.isValid && <XCircleIcon className="h-3 w-3 text-destructive" />}
                {validation.isValid && parameter.defaultValue && (
                  <CheckCircleIcon className="h-3 w-3 text-green-500" />
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

import { GeneratedCommand } from "../generated-command";
import { JsonOutput } from "../json-output";
import { ToolRenderer, defaultComponents } from "../tool-renderer";
import { HelpMenu } from "./help-menu";
import { toolBuilderStore, toolBuilderActions } from "./tool-editor.store";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
