    { condition: (p) => p.parameterType === "Option" && p.dataType === "Enum", component: (ctx) => <OptionEnumInput {...ctx} /> },
    { condition: (p) => p.parameterType === "Option" && p.dataType === "Boolean", component: (ctx) => <OptionBooleanInput {...ctx} /> },
    { condition: (p) => p.parameterType === "Option", component: (ctx) => <OptionTextInput {...ctx} /> },
